import React from "react";

export default function LoansScreen({ loans }) {
  return (
    <div className="px-6 pb-24">
      <h1 className="text-2xl font-bold mb-6">Your Loans</h1>
      {loans.length === 0 ? (
        <p className="text-gray-500">No active loans.</p>
      ) : (
        <div className="space-y-4">
          {loans.map((loan) => (
            <div key={loan.id} className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm">
              <h2 className="font-semibold text-gray-800">{loan.title}</h2>
              <p className="text-sm text-gray-500">Amount Borrowed: ${loan.amount}</p>
              <p className="text-sm text-gray-500">Due Date: {loan.dueDate}</p>
              <p className="text-red-600 font-bold mt-2">Outstanding: ${loan.outstanding}</p>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
